import React from 'react'
import styled from 'styled-components'
import ArticleCard from './ArticleCard'


const ArticleCardsWrapper = styled.div `
width:80%;
margin:0 auto;
display:flex;
`

const Title = styled.div `
font-size:1.3rem;
color:#1C1C1C;
font-weight:900;
margin:20px 0;
`


export default function RelatedArticlesSection () {

	return (
		<>
			<Title>Realted Maison Margiela Articles</Title>
			<ArticleCardsWrapper>
				<ArticleCard/>
				<ArticleCard/>
				<ArticleCard/>
				<ArticleCard/>
			</ArticleCardsWrapper>
		</>
	)
}
